#include <stdio.h>
#include <string.h>

int main() {
    char text[] = "Merhaba dunya bu bir test metni Bu metin kelime sayma icin kullanilacak Merhaba tekrar";

    int charCount = strlen(text);
    int wordCount = 0;
    int inWord = 0;

    for (int i = 0; i < charCount; i++) {
        if (text[i] != ' ') {
            if (!inWord) {
                wordCount++;
                inWord = 1;
            }
        } else {
            inWord = 0;
        }
    }

    printf("Toplam kelime sayisi: %d\n", wordCount);
    printf("Toplam karakter sayisi: %d\n", charCount);

    // En uzun kelime
    char copy[200];
    strcpy(copy, text);

    char* token = strtok(copy, " ");
    char longestWord[50] = "";

    while (token != NULL) {
        if (strlen(token) > strlen(longestWord)) {
            strcpy(longestWord, token);
        }
        token = strtok(NULL, " ");
    }

    printf("\nEn uzun kelime: '%s' (%lu karakter)\n", longestWord, strlen(longestWord));

    // Ortalama kelime uzunlugu (boslukları cikararak)
    int letterCount = 0;
    for (int i = 0; i < charCount; i++) {
        if (text[i] != ' ') letterCount++;
    }
    double avgLength = (double)letterCount / wordCount;
    printf("Ortalama kelime uzunlugu: %.2f\n", avgLength);

    return 0;
}
